return ['x-generator'=>'GlotPress/4.0.0-rc.1','translation-revision-date'=>'2025-03-20 16:45:05+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'RocketGenius - Gravity Forms reCAPTCHA','language'=>'es','messages'=>['You have reached the quota limit for reCAPTCHA set by Google. Please check the quota on your %sreCAPTCHA Account%s.'=>'Has alcanzado el límite de cuota de reCAPTCHA establecido por Google. Comprueba la cuota en tu cuenta de %sreCAPTCHA%s.','Value defined using the %s constant.'=>'Valor definido utilizando la constante %s.','Click here to learn more about reCAPTCHA.'=>'Haz clic aquí para aprender más sobre reCAPTCHA.','Score'=>'Puntuación','reCAPTCHA'=>'reCAPTCHA','reCAPTCHA Score'=>'Puntuación de reCAPTCHA','Disable reCAPTCHA v3 for this form.'=>'Desactivar reCAPTCHA v3 para este formulario.','Score threshold must be between 0.0 and 1.0'=>'El umbral de la puntuación debe estar entre 0.0 y 1.0','Unexpected field type.'=>'Tipo de campo inesperado.','The default threshold is 0.5.'=>'El umbral por defecto es 0.5.','If the score is less than or equal to this threshold, the form submission will be sent to spam.'=>'Si la puntuación es menor o igual a este umbral, el envío del formulario se enviará a spam.','reCAPTCHA v3 returns a score (1.0 is very likely a good interaction, 0.0 is very likely a bot).'=>'reCAPTCHA v3 devuelve una puntuación (1.0 es muy probable que sea una buena interacción , 0.0 es muy probable que sea un bot)','check out our documentation.'=>'Consulta nuestra documentación.','For more information on reCAPTCHA, which version is right for you, and how to add it to your forms,'=>'Para más información sobre reCAPTCHA, sobre qué versión es la mejor para ti, y cómo añadirlo a tus formularios.','reCAPTCHA v2 (Checkbox) - Requires a user to click a checkbox to indicate that they are not a robot and displays a challenge if the activity is suspicious'=>'reCAPTCHA v2 (Casilla de verificación) - Necesita hacer clic en una casilla de verificación para indicar que no son robots y muestra un desafío si la actividad es sospechosa.','Read more about reCAPTCHA.'=>'Lee más acerca de reCAPTCHA.','To activate reCAPTCHA v2 on your form, simply add the CAPTCHA field in the form editor.'=>'Para activar reCAPTCHA v2 en tu formulario, sólo tienes que añadir el campo CAPTCHA en el editor de formulario.','Please note, only v2 keys are supported and checkbox keys are not compatible with invisible reCAPTCHA.'=>'Ten en cuenta que solo se admiten las claves v2 y que las claves de las casillas de verificación no son compatibles con los reCAPTCHA invisibles.','reCAPTCHA v2 (Invisible) - Displays a badge on your form and will present a challenge to the user if the activity is suspicious e.g. select the traffic lights.'=>'reCAPTCHA v2 (Invisible) - Muestra una insignia en tu formulario y le presentará un desafío al usuario si la actividad sospechosa, por ejemplo, seleccionar semáforos.','When reCAPTCHA v3 is configured, it is enabled automatically on all forms by default. It can be disabled for specific forms in the form settings.'=>'Cuando reCAPTCHA v3 está configurado, se activa automáticamente en todos los formularios por defecto. Se puede desactivar para determinados formularios en los ajustes de formulario.','All submissions are accepted and suspicious submissions are marked as spam.'=>'Todos los envíos son aceptados y los envíos sospechosos son marcados como spam.','reCAPTCHA v3 - Adds a script to every page of your site and uploads form content for processing by Google.'=>'reCAPTCHA v3 - Añade un script a cada página de tu web y sube el contenido del formulario para ser procesado por Google.','Gravity Forms integrates with three types of Google reCAPTCHA.'=>'Gravity Forms integra tres tipos de Google reCAPTCHA.','By adding reCAPTCHA to your forms, you can deter automated software from submitting form entries, while still ensuring a user-friendly experience for real people.'=>'Al agregar reCAPTCHA a tus formularios, puedes disuadir al software automatizado de enviar entradas de formularios, al tiempo que garantizas una buena experiencia para los usuarios que sean personas reales.','Google reCAPTCHA is a free anti-spam service that protects your website from fraud and abuse.'=>'Google reCAPTCHA es un servicio anti-spam gratuito que protege tu web de fraudes y abusos.','reCAPTCHA keys are invalid.'=>'Las claves de reCAPTCHA no son válidas.','Validate Keys'=>'Validar claves','Invisible'=>'Invisible','Checkbox'=>'Casilla','Type'=>'Tipo','reCAPTCHA v2'=>'reCAPTCHA v2','I have added the reCAPTCHA branding, terms of service and privacy policy to my site. '=>'He agregado la marca reCAPTCHA, los términos de servicio su la política de privacidad a mi web.','By default reCAPTCHA v3 displays a badge on every page of your site with links to the Google terms of service and privacy policy. You are allowed to hide the badge as long as you include the reCAPTCHA branding and links visibly in the user flow.'=>'Por defecto reCAPTCHA v3 muestra una insignia en cada página de tu web con enlaces a los térmios de servicios y políticas de privacidad. Puedes ocultar la insignia siempre que incluyas el branding de reCAPTCHA y los enlaces visibles en el flujo de usuarios.','Disable Google reCAPTCHA Badge'=>'Desactivar la insignia de Google reCAPTCHA','Score Threshold'=>'Umbral de puntuación','Secret Key'=>'Clave secreta','Site Key'=>'Clave del sitio','reCAPTCHA Settings'=>'Ajustes de reCAPTCHA','Gravity Forms'=>'Gravity Forms','Enhance Gravity Forms with support for Google reCAPTCHA.'=>'Mejorar Gravity Forms con el soporte de Google reCAPTCHA.','https://gravityforms.com'=>'https://gravityforms.com','Gravity Forms reCAPTCHA Add-On'=>'Gravity Forms reCAPTCHA Add-On']];